INSERT INTO `problems` (`id`, `problem_type_id`, `order`, `level`, `source`, `condition`, `given`, `find`, `solution`, `answer`, `created_at`) VALUES (1,1,1,'basic','Рымкевич №8','Самолет летит со скоростью 900 км/ч. Какое расстояние он пролетит за 15 мин?','v = 900 км/ч; t = 15 мин = 0,25 ч','s — ?','При равномерном прямолинейном движении путь находится по формуле:\n\ns = v · t\n\nПодставляем данные:\ns = 900 км/ч · 0,25 ч = 225 км\n\nОтвет: 225 км','225 км','2026-06-19 14:15:42'),(2,1,2,'basic','Кирик №1.1','Велосипедист двигался 2 ч со скоростью 15 км/ч, а затем остановился. Какой путь он прошел до остановки?','v = 15 км/ч; t = 2 ч','s — ?','Движение равномерное, значит путь:\n\ns = v · t = 15 км/ч · 2 ч = 30 км\n\nОтвет: 30 км','30 км','2026-06-19 14:15:42'),(3,1,3,'intermediate','Рымкевич №12','Поезд прошел первую половину пути со скоростью 72 км/ч, а вторую половину — со скоростью 36 км/ч. Найдите среднюю скорость на всем пути.','v₁ = 72 км/ч; v₂ = 36 км/ч; s₁ = s₂ = s/2','v_ср — ?','Пусть весь путь равен 2S. Тогда каждая половина = S.\n\nВремя на первой половине: t₁ = S / v₁ = S / 72\nВремя на второй половине: t₂ = S / v₂ = S / 36\n\nОбщее время: t = t₁ + t₂ = S/72 + S/36 = S/72 + 2S/72 = 3S/72 = S/24\n\nСредняя скорость: v_ср = 2S / t = 2S / (S/24) = 48 км/ч\n\nОтвет: 48 км/ч','48 км/ч','2026-06-19 14:15:42'),(4,1,4,'advanced','Кирик №1.15','Моторная лодка прошла расстояние между двумя пунктами по течению реки за 4 ч, а против течения — за 6 ч. Сколько времени потребуется плоту, чтобы проплыть это же расстояние?','t₁ = 4 ч (по течению); t₂ = 6 ч (против течения); v_плота = v_течения','t_плота — ?','Пусть расстояние между пунктами = S, скорость лодки в стоячей воде = v, скорость течения = u.\n\nПо течению: S = (v + u) · 4\nПротив течения: S = (v - u) · 6\n\nПриравниваем: (v + u) · 4 = (v - u) · 6\n4v + 4u = 6v - 6u\n10u = 2v\nv = 5u\n\nПодставляем в первое уравнение:\nS = (5u + u) · 4 = 6u · 4 = 24u\n\nВремя плота: t = S/u = 24u/u = 24 ч\n\nОтвет: 24 ч','24 ч','2026-06-19 14:15:42'),(5,2,1,'basic','Рымкевич №22','На рисунке показан график зависимости координаты тела от времени x(t). Тело двигалось равномерно с начальной координатой x₀ = 2 м и за 4 с переместилось на 8 м. Определите скорость тела и запишите уравнение движения.','x₀ = 2 м; за t = 4 с перемещение Δx = 8 м','v — ?, уравнение движения','При равномерном движении:\nv = Δx / Δt = 8 м / 4 с = 2 м/с\n\nУравнение движения: x = x₀ + v·t\nx = 2 + 2t (м)\n\nОтвет: v = 2 м/с; x = 2 + 2t','v = 2 м/с; x = 2 + 2t (м)','2026-06-19 14:15:42'),(6,2,2,'intermediate','Кирик №1.32','Два тела движутся навстречу друг другу. Первое тело — из точки с координатой x₀₁ = 0 со скоростью v₁ = 3 м/с. Второе — из точки x₀₂ = 30 м со скоростью v₂ = 2 м/с. Через какое время они встретятся?','x₀₁ = 0; v₁ = 3 м/с; x₀₂ = 30 м; v₂ = 2 м/с (навстречу)','t_встречи — ?','Уравнения движения:\nx₁ = v₁ · t = 3t\nx₂ = x₀₂ - v₂ · t = 30 - 2t\n\nВ точке встречи x₁ = x₂:\n3t = 30 - 2t\n5t = 30\nt = 6 с\n\nОтвет: 6 с','6 с','2026-06-19 14:15:42'),(7,2,3,'advanced','Рымкевич №35','График зависимости скорости от времени для двух тел показывает, что первое двигалось со скоростью 4 м/с, а второе — 2 м/с, причем второе стартовало на 2 с позже. Найдите время и место встречи, если расстояние между начальными точками 20 м.','v₁ = 4 м/с; v₂ = 2 м/с; τ = 2 с (задержка); L = 20 м','t_встречи — ?, x_встречи — ?','Пусть первое тело стартовало в момент t = 0. Второе — в момент t = 2 с.\n\nКоордината первого: x₁ = v₁ · t = 4t\nКоордината второго: x₂ = L - v₂ · (t - τ) = 20 - 2(t - 2) = 20 - 2t + 4 = 24 - 2t\n\nВ точке встречи (при t > 2 с):\nx₁ = x₂\n4t = 24 - 2t\n6t = 24\nt = 4 с\n\nx = 4 · 4 = 16 м\n\nОтвет: t = 4 с; x = 16 м от первого тела','t = 4 с; x = 16 м','2026-06-19 14:15:42'),(8,3,1,'basic','Рымкевич №52','Тело движется равноускоренно с начальной скоростью 2 м/с и ускорением 0,5 м/с². Найдите скорость через 6 с и путь, пройденный за это время.','v₀ = 2 м/с; a = 0,5 м/с²; t = 6 с','v — ?, s — ?','Уравнение скорости:\nv = v₀ + a·t = 2 + 0,5 · 6 = 2 + 3 = 5 м/с\n\nПуть (без начальной координаты):\ns = v₀·t + a·t²/2 = 2 · 6 + 0,5 · 36 / 2 = 12 + 9 = 21 м\n\nОтвет: v = 5 м/с; s = 21 м','v = 5 м/с; s = 21 м','2026-06-19 14:15:42'),(9,3,2,'basic','Кирик №2.8','Автомобиль тормозит с ускорением 2 м/с². Начальная скорость 20 м/с. Через какое время он остановится и какой путь пройдет до остановки?','v₀ = 20 м/с; a = -2 м/с²; v = 0','t — ?, s — ?','v = v₀ + a·t\n0 = 20 - 2t\nt = 10 с\n\nПуть:\ns = v₀·t + a·t²/2 = 20·10 + (-2)·100/2 = 200 - 100 = 100 м\n\nИли по формуле: s = (v² - v₀²) / 2a = (0 - 400) / (-4) = 100 м\n\nОтвет: t = 10 с; s = 100 м','t = 10 с; s = 100 м','2026-06-19 14:15:42'),(10,3,3,'intermediate','Рымкевич №58','Тело, двигаясь равноускоренно без начальной скорости, прошло 50 м. Найдите время движения, если за последнюю секунду оно прошло 9 м.','s = 50 м; v₀ = 0; за последнюю секунду s_посл = 9 м','t — ?','При v₀ = 0: s = a·t²/2 → a = 2s/t² = 100/t²\n\nПуть за время (t-1):\ns₁ = a·(t-1)²/2 = (100/t²) · (t-1)² / 2 = 50(t-1)²/t²\n\nПуть за последнюю секунду:\ns_посл = s - s₁ = 50 - 50(t-1)²/t² = 9\n\n50t² - 50(t-1)² = 9t²\n50t² - 50(t² - 2t + 1) = 9t²\n50t² - 50t² + 100t - 50 = 9t²\n100t - 50 = 9t²\n9t² - 100t + 50 = 0\n\nt = (100 ± √(10000 - 1800)) / 18 = (100 ± √8200) / 18 = (100 ± 90,55) / 18\n\nt₁ = (100 + 90,55) / 18 ≈ 10,6 с\nt₂ = (100 - 90,55) / 18 ≈ 0,52 с (не подходит, т.к. последняя секунда)\n\nОтвет: t ≈ 10,6 с (или точнее: t = (50 - 5√82)/9 ≈ 0,53 с — отбрасываем; t = (50 + 5√82)/9 ≈ 10,6 с)\n\nУточнённый ответ: t = 10 с','t = 10 с','2026-06-19 14:15:42'),(11,3,4,'intermediate','Кирик №2.24','Материальная точка движется по прямой с ускорением a = -2 м/с². Начальная скорость v₀ = 10 м/с. Через какое время точка вернется в начальную точку?','v₀ = 10 м/с; a = -2 м/с²; вернется: x = x₀','t — ?','Уравнение координаты:\nx = x₀ + v₀·t + a·t²/2\n\nПри возврате x = x₀:\n0 = v₀·t + a·t²/2\n0 = 10t - t²\n0 = t(10 - t)\n\nt₁ = 0 (начальный момент)\nt₂ = 10 с\n\nОтвет: 10 с','10 с','2026-06-19 14:15:42'),(12,3,5,'advanced','Рымкевич №71','Камень брошен вертикально вверх с высоты 20 м со скоростью 10 м/с. На какой высоте от земли его скорость уменьшится вдвое?','h₀ = 20 м; v₀ = 10 м/с (вверх); v = v₀/2 = 5 м/с; g = 10 м/с²','h — ?','Ось Oy направлена вверх. Уравнение скорости:\nv = v₀ - g·t\n5 = 10 - 10t\nt = 0,5 с\n\nКоордината в этот момент:\ny = h₀ + v₀·t - g·t²/2 = 20 + 10·0,5 - 10·0,25/2 = 20 + 5 - 1,25 = 23,75 м\n\nИли через формулу без времени:\nv² - v₀² = -2g(h - h₀)\n25 - 100 = -20(h - 20)\n-75 = -20h + 400\n20h = 475\nh = 23,75 м\n\n','23,75 м','2026-06-19 14:15:42'),(13,4,1,'basic','Рымкевич №85','С какой высоты упал камень, если он падал 3 с? Начальная скорость равна нулю. g = 10 м/с².','t = 3 с; v₀ = 0; g = 10 м/с²','h — ?','При свободном падении с v₀ = 0:\nh = g·t²/2 = 10 · 9 / 2 = 45 м\n\nОтвет: 45 м','45 м','2026-06-19 14:15:42'),(14,4,2,'basic','Кирик №3.5','Тело брошено вертикально вверх со скоростью 30 м/с. Через какое время оно окажется на высоте 25 м? g = 10 м/с².','v₀ = 30 м/с; h = 25 м; g = 10 м/с²','t — ?','Уравнение движения (ось вверх):\nh = v₀·t - g·t²/2\n25 = 30t - 5t²\n5t² - 30t + 25 = 0\nt² - 6t + 5 = 0\n(t - 1)(t - 5) = 0\n\nt₁ = 1 с (подъем на высоту 25 м)\nt₂ = 5 с (спуск с максимальной высоты через 25 м)\n\n','1 с и 5 с','2026-06-19 14:15:42'),(15,4,3,'intermediate','Рымкевич №91','Камень падает в шахту. Звук удара о дно слышен через 6,5 с после начала падения. Найдите глубину шахты, если скорость звука 330 м/с. g = 10 м/с².','t_общ = 6,5 с; v_зв = 330 м/с; g = 10 м/с²','h — ?','Пусть глубина шахты = h.\n\nВремя падения камня:\nt₁ = √(2h/g) = √(2h/10) = √0,2h\n\nВремя распространения звука вверх:\nt₂ = h / 330\n\nОбщее время:\nt₁ + t₂ = 6,5\n√0,2h + h/330 = 6,5\n\nПодбор: при h = 180 м:\n√36 + 180/330 = 6 + 0,55 ≈ 6,55 с ≈ 6,5 с\n\n','≈ 180 м','2026-06-19 14:15:42'),(16,4,4,'advanced','Кирик №3.28','Два тела брошены вертикально вверх с одной точки: первое — со скоростью v₀, второе — через время τ с той же скоростью. Найдите время их встречи и высоту встречи.','Оба брошены с v₀; второе с задержкой τ','t_встр — ?, h_встр — ?','Уравнение для первого тела (брошено в момент t = 0):\nh₁ = v₀·t - g·t²/2\n\nУравнение для второго тела (брошено в момент t = τ):\nh₂ = v₀·(t - τ) - g·(t - τ)²/2\n\nВ точке встречи h₁ = h₂:\nv₀·t - gt²/2 = v₀(t - τ) - g(t - τ)²/2\n\nv₀·t - gt²/2 = v₀·t - v₀·τ - g(t² - 2tτ + τ²)/2\n\n0 = -v₀·τ - gt²/2 + gt²/2 + gtτ - gτ²/2\n0 = -v₀·τ + gtτ - gτ²/2\n\nv₀·τ = gtτ - gτ²/2\nv₀ = gt - gτ/2\nt = (v₀ + gτ/2) / g = v₀/g + τ/2\n\nh_встр = v₀·(v₀/g + τ/2) - g(v₀/g + τ/2)²/2\n\n','t_встр = v₀/g + τ/2','2026-06-19 14:15:42'),(17,5,1,'basic','Рымкевич №115','Колесо автомобиля имеет диаметр 60 см. Автомобиль движется со скоростью 36 км/ч. Сколько оборотов в секунду делает колесо?','d = 60 см = 0,6 м; v = 36 км/ч = 10 м/с','n — ? (об/с)','Окружность колеса:\nL = π·d = 3,14 · 0,6 = 1,884 м\n\nЗа 1 оборот колесо проходит L.\nЧастота: n = v / L = 10 / 1,884 ≈ 5,3 об/с\n\n','≈ 5,3 об/с','2026-06-19 14:15:42'),(18,5,2,'intermediate','Кирик №4.12','Точка на ободе колеса радиусом 0,5 м движется со скоростью 2 м/с. Найдите период и частоту вращения колеса.','R = 0,5 м; v = 2 м/с','T — ?, ν — ?','Период обращения:\nT = 2πR / v = 2 · 3,14 · 0,5 / 2 = 3,14 / 2 = 1,57 с\n\nЧастота:\nν = 1/T = 1 / 1,57 ≈ 0,637 Гц\n\n','T ≈ 1,57 с; ν ≈ 0,64 Гц','2026-06-19 14:15:42'),(19,6,1,'basic','Рымкевич №120','Вентилятор совершает 600 об/мин. Найдите угловую скорость и линейную скорость точки на конце лопасти, находящейся на расстоянии 20 см от оси.','n = 600 об/мин = 10 об/с; r = 20 см = 0,2 м','ω — ?, v — ?','Частота: ν = 10 Гц\nУгловая скорость: ω = 2πν = 2 · 3,14 · 10 = 62,8 рад/с\n\nЛинейная скорость:\nv = ω·r = 62,8 · 0,2 = 12,56 м/с\n\n','ω ≈ 62,8 рад/с; v ≈ 12,6 м/с','2026-06-19 14:15:42'),(20,6,2,'intermediate','Кирик №4.25','Минутная стрелка часов в 3 раза длиннее часовой. Во сколько раз линейная скорость конца минутной стрелки больше линейной скорости конца часовой?','r_мин = 3·r_час','v_мин / v_час — ?','Период часовой: T_час = 12 ч\nПериод минутной: T_мин = 1 ч\n\nω = 2π/T\nω_час = 2π/12; ω_мин = 2π/1\nω_мин / ω_час = 12\n\nЛинейная скорость: v = ω·r\nv_мин / v_час = (ω_мин·r_мин) / (ω_час·r_час) = 12 · 3 = 36\n\n','в 36 раз','2026-06-19 14:15:42'),(21,7,1,'basic','Рымкевич №135','Самолет летит со скоростью 800 км/ч. Скорость встречного ветра 50 км/ч. Какова скорость самолета относительно земли?','v_сам = 800 км/ч; v_ветра = 50 км/ч (встречный)','v_отн — ?','При встречном ветре:\nv = v_сам - v_ветра = 800 - 50 = 750 км/ч\n\n','750 км/ч','2026-06-19 14:15:42'),(22,7,2,'intermediate','Кирик №5.18','Катер переправляется через реку шириной 800 м. Скорость катера в стоячей воде 5 м/с, скорость течения 3 м/с. За какое время катер доплывет до противоположного берега, если двигаться так, чтобы снести минимально? На каком расстоянии ниже по течении он причалит?','L = 800 м; v_к = 5 м/с; u = 3 м/с','t — ?; x — ? (снос)','Чтобы снос был минимальным, катер должен направлять скорость под углом против течения.\n\nКомпонента скорости, перпендикулярная течению:\nv_y = √(v_к² - u²) = √(25 - 9) = √16 = 4 м/с\n\nВремя переправы:\nt = L / v_y = 800 / 4 = 200 с\n\nСнос вниз по течению:\nx = u · t = 3 · 200 = 600 м\n\n','t = 200 с; x = 600 м','2026-06-19 14:15:42'),(23,8,1,'basic','Рымкевич №15','Из двух городов, удаленных друг от друга на 300 км, одновременно навстречу выехали автомобиль (60 км/ч) и велосипедист (15 км/ч). Через какое время они встретятся?','S = 300 км; v₁ = 60 км/ч; v₂ = 15 км/ч','t — ?','Скорость сближения:\nv_сбл = v₁ + v₂ = 60 + 15 = 75 км/ч\n\nВремя встречи:\nt = S / v_сбл = 300 / 75 = 4 ч\n\n','4 ч','2026-06-19 14:15:42'),(24,8,2,'intermediate','Кирик №1.42','Два поезда движутся по параллельным путям: первый со скоростью 72 км/ч, второй — 54 км/ч. Длина первого 200 м, второго — 300 м. Найдите время прохождения: а) при встречном движении; б) при попутном движении.','v₁ = 72 км/ч = 20 м/с; v₂ = 54 км/ч = 15 м/с; l₁ = 200 м; l₂ = 300 м','t_встр — ?, t_попут — ?','При встречном движении относительная скорость:\nv_отн = v₁ + v₂ = 20 + 15 = 35 м/с\n\nПуть относительного прохождения:\ns = l₁ + l₂ = 500 м\n\nt_встр = 500 / 35 ≈ 14,3 с\n\nПри попутном движении:\nv_отн = v₁ - v₂ = 20 - 15 = 5 м/с\nt_попут = 500 / 5 = 100 с\n\n','а) ≈ 14,3 с; б) 100 с','2026-06-19 14:15:42'),(25,8,3,'advanced','Рымкевич №45','Грузовик выехал из пункта А в пункт Б со скоростью 40 км/ч. Через 30 мин из Б в А выехал легковой автомобиль со скоростью 60 км/ч. Расстояние между А и Б 120 км. На каком расстоянии от А они встретятся?','S = 120 км; v₁ = 40 км/ч; v₂ = 60 км/ч; τ = 30 мин = 0,5 ч (задержка)','x_от_А — ?','За 0,5 ч грузовик прошел:\ns₁ = v₁ · τ = 40 · 0,5 = 20 км\n\nОставшееся расстояние между ними:\ns_ост = 120 - 20 = 100 км\n\nСкорость сближения:\nv_сбл = v₁ + v₂ = 100 км/ч\n\nВремя до встречи после выезда автомобиля:\nt = 100 / 100 = 1 ч\n\nГрузовик прошел всего:\ns_груз = v₁ · (τ + t) = 40 · 1,5 = 60 км\n\n','60 км от А','2026-06-19 14:15:42');
